-- ─── Helper function: find users within radius (km) ──────────────────────────
-- Uses Haversine formula — no PostGIS extension required
CREATE OR REPLACE FUNCTION find_nearby_satsang_seekers(
  p_lat   FLOAT,
  p_lon   FLOAT,
  p_km    FLOAT DEFAULT 10.0,
  p_limit INT   DEFAULT 20
)
RETURNS TABLE (
  id            UUID,
  full_name     TEXT,
  username      TEXT,
  avatar_url    TEXT,
  tradition     TEXT,
  sampradaya    TEXT,
  neighbourhood TEXT,
  city          TEXT,
  distance_km   FLOAT
)
LANGUAGE sql
STABLE
SECURITY DEFINER
AS $$
  SELECT
    p.id,
    p.full_name,
    p.username,
    p.avatar_url,
    p.tradition,
    p.sampradaya,
    p.neighbourhood,
    p.city,
    -- Haversine distance in km
    ROUND(CAST(
      6371 * 2 * ASIN(SQRT(
        POWER(SIN(RADIANS((p.latitude  - p_lat) / 2)), 2) +
        COS(RADIANS(p_lat)) * COS(RADIANS(p.latitude)) *
        POWER(SIN(RADIANS((p.longitude - p_lon) / 2)), 2)
      ))
    AS NUMERIC), 1)::FLOAT AS distance_km
  FROM profiles p
  WHERE
    p.location_visible    = true
    AND p.looking_for_satsang = true
    AND p.latitude  IS NOT NULL
    AND p.longitude IS NOT NULL
    AND p.id != auth.uid()
    -- Bounding box pre-filter (fast, avoids full table scan)
    AND p.latitude  BETWEEN p_lat - (p_km / 111.0) AND p_lat + (p_km / 111.0)
    AND p.longitude BETWEEN p_lon - (p_km / (111.0 * COS(RADIANS(p_lat))))
                        AND p_lon + (p_km / (111.0 * COS(RADIANS(p_lat))))
  ORDER BY distance_km ASC
  LIMIT p_limit;
$$;

-- Grant execute to authenticated users
GRANT EXECUTE ON FUNCTION find_nearby_satsang_seekers TO authenticated;


-- --------------------------------------------------
-- Archive Migration: migration-v10-signup-metadata.sql
-- --------------------------------------------------

-- ─── Migration v10 — Persist signup metadata in handle_new_user ─────────────
-- Fixes profile data being lost when email confirmation is enabled.
-- The signup form now sends dharmic/profile fields in raw_user_meta_data,
-- and this trigger copies them into public.profiles as soon as auth.users is created.

CREATE OR REPLACE FUNCTION public.handle_new_user()
RETURNS TRIGGER AS $$
DECLARE
  v_seeking text[] := ARRAY[]::text[];
BEGIN
  IF jsonb_typeof(NEW.raw_user_meta_data->'seeking') = 'array' THEN
    v_seeking := ARRAY(
      SELECT jsonb_array_elements_text(NEW.raw_user_meta_data->'seeking')
    );
  END IF;

  INSERT INTO public.profiles (
    id,
    full_name,
    username,
    tradition,
    neighbourhood,
    city,
    country,
    latitude,
    longitude,
    sampradaya,
    ishta_devata,
    spiritual_level,
    seeking,
    kul,
    gotra
  )
  VALUES (
    NEW.id,
    COALESCE(NULLIF(NEW.raw_user_meta_data->>'full_name', ''), 'Sanatani'),
    COALESCE(NULLIF(NEW.raw_user_meta_data->>'username', ''), 'user_' || substr(NEW.id::text, 1, 8)),
    NULLIF(NEW.raw_user_meta_data->>'tradition', ''),
    NULLIF(NEW.raw_user_meta_data->>'neighbourhood', ''),
    NULLIF(NEW.raw_user_meta_data->>'city', ''),
    NULLIF(NEW.raw_user_meta_data->>'country', ''),
    NULLIF(NEW.raw_user_meta_data->>'latitude', '')::double precision,
    NULLIF(NEW.raw_user_meta_data->>'longitude', '')::double precision,
    NULLIF(NEW.raw_user_meta_data->>'sampradaya', ''),
    NULLIF(NEW.raw_user_meta_data->>'ishta_devata', ''),
    COALESCE(NULLIF(NEW.raw_user_meta_data->>'spiritual_level', ''), 'jigyasu'),
    v_seeking,
    NULLIF(NEW.raw_user_meta_data->>'kul', ''),
    NULLIF(NEW.raw_user_meta_data->>'gotra', '')
  );

  RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;


