    ELSE COALESCE(tradition, 'all')
  END,
  is_shared = CASE name
    WHEN 'Guru Purnima' THEN true
    WHEN 'Diwali' THEN true
    ELSE false
  END
WHERE tradition IS NULL OR source_name = 'Sanatana Sangam editorial calendar';

