-- --------------------------------------------------
-- Archive Migration: migration-v34-sattvic-sessions.sql
-- --------------------------------------------------

-- ─── Migration v34: sattvic_sessions table ────────────────────────────────────
-- Stores meditation, breathwork, and chanting sessions from the Sattvic (Zen) Mode.
-- Run this in: Supabase Dashboard → SQL Editor

create table if not exists public.sattvic_sessions (
  id               uuid primary key default gen_random_uuid(),
  user_id          uuid not null references public.profiles(id) on delete cascade,
  mode             text not null check (mode in ('breath', 'chant', 'reading', 'silent')),
  duration_secs    integer not null,
  environment      text not null, -- e.g., 'temple', 'forest', 'cosmos'
  mantra           text,          -- if mode was 'chant'
  completed_at     timestamptz not null default now(),
  created_at       timestamptz not null default now()
);

-- Indexes for querying history
create index if not exists sattvic_sessions_user_id_idx on public.sattvic_sessions(user_id);
create index if not exists sattvic_sessions_completed_at_idx on public.sattvic_sessions(completed_at);

-- RLS
alter table public.sattvic_sessions enable row level security;

create policy "Users can view their own sattvic sessions"
  on public.sattvic_sessions for select
  using (auth.uid() = user_id);

create policy "Users can insert their own sattvic sessions"
  on public.sattvic_sessions for insert
  with check (auth.uid() = user_id);

create policy "Users can update their own sattvic sessions"
  on public.sattvic_sessions for update
  using (auth.uid() = user_id);

create policy "Users can delete their own sattvic sessions"
  on public.sattvic_sessions for delete
  using (auth.uid() = user_id);


-- --------------------------------------------------
-- Archive Migration: migration-v35-hero-assets.sql
-- --------------------------------------------------

-- Hero artwork registry for dynamic Home hero selection.
-- Physical files live in Supabase Storage bucket `hero-assets`.
-- This table stores metadata/matching rules only.

insert into storage.buckets (id, name, public)
values ('hero-assets', 'hero-assets', true)
on conflict (id) do update set public = true;

create table if not exists public.hero_assets (
  id uuid primary key default gen_random_uuid(),
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),
  label text not null,
  hero_image text not null,
  hero_alt text not null,
  object_position text not null default 'center 24%',
  traditions text[] not null default '{}',
  sampradayas text[] not null default '{}',
  ishta_devatas text[] not null default '{}',
  festival_slugs text[] not null default '{}',
  tags text[] not null default '{}',
  priority integer not null default 0,
  is_active boolean not null default true,
  uploaded_by text
);

create index if not exists hero_assets_active_idx on public.hero_assets (is_active, priority desc);
create index if not exists hero_assets_traditions_idx on public.hero_assets using gin (traditions);
create index if not exists hero_assets_festival_slugs_idx on public.hero_assets using gin (festival_slugs);

create or replace function public.set_hero_assets_updated_at()
returns trigger as $$
begin
  new.updated_at = now();
  return new;
end;
$$ language plpgsql;

drop trigger if exists trg_hero_assets_updated_at on public.hero_assets;
create trigger trg_hero_assets_updated_at
before update on public.hero_assets
for each row execute function public.set_hero_assets_updated_at();


