CREATE POLICY "Guardians can manage kul assets"
  ON storage.objects FOR ALL
  TO authenticated
  USING (
    bucket_id = 'avatars'
    AND (string_to_array(name, '/'))[1] = 'kuls'
    AND (string_to_array(name, '/'))[2] = public.auth_kul_id()::text
    AND public.auth_kul_role() = 'guardian'
  )
  WITH CHECK (
    bucket_id = 'avatars'
    AND (string_to_array(name, '/'))[1] = 'kuls'
    AND (string_to_array(name, '/'))[2] = public.auth_kul_id()::text
    AND public.auth_kul_role() = 'guardian'
  );

