-- --------------------------------------------------
-- Migration: 015_founding_member.sql
-- --------------------------------------------------

-- ─── Migration 015: Founding Member System ────────────────────────────────────
-- Adds founding_number sequence to waitlist + founding member columns to profiles
-- Run in Supabase SQL editor or via supabase db push
-- ─────────────────────────────────────────────────────────────────────────────

-- 1. Founding number sequence for the waitlist
CREATE SEQUENCE IF NOT EXISTS waitlist_founding_seq START 1 INCREMENT 1;

-- 2. Add new columns to waitlist
ALTER TABLE waitlist
  ADD COLUMN IF NOT EXISTS founding_number INTEGER DEFAULT nextval('waitlist_founding_seq'),
  ADD COLUMN IF NOT EXISTS timezone        TEXT    NULL,
  ADD COLUMN IF NOT EXISTS email_sent      BOOLEAN NOT NULL DEFAULT FALSE;

-- Make founding_number owned by the column so it's dropped together
ALTER SEQUENCE waitlist_founding_seq OWNED BY waitlist.founding_number;

-- Keep one row per email before adding a case-insensitive uniqueness guard.
-- The earliest row keeps the founding spot.
WITH ranked AS (
  SELECT
    id,
    row_number() OVER (
      PARTITION BY lower(email)
      ORDER BY created_at ASC NULLS LAST, id ASC
    ) AS rn
  FROM waitlist
)
DELETE FROM waitlist
USING ranked
WHERE waitlist.id = ranked.id
  AND ranked.rn > 1;

-- Backfill existing rows with sequential numbers.
DO $$
DECLARE r RECORD; n INT := 1;
BEGIN
  FOR r IN SELECT id FROM waitlist WHERE founding_number IS NULL ORDER BY created_at ASC NULLS LAST, id ASC LOOP
    UPDATE waitlist SET founding_number = n WHERE id = r.id;
    n := n + 1;
  END LOOP;
END $$;

-- Move the sequence beyond the largest existing founding number.
DO $$
DECLARE max_num INT;
BEGIN
  SELECT COALESCE(MAX(founding_number), 0) INTO max_num FROM waitlist;
  PERFORM setval('waitlist_founding_seq', GREATEST(max_num, 1), max_num > 0);
END $$;

-- 3. Add founding member columns to profiles (populated on first app login after launch)
ALTER TABLE profiles
  ADD COLUMN IF NOT EXISTS is_founding_member BOOLEAN NOT NULL DEFAULT FALSE,
  ADD COLUMN IF NOT EXISTS founding_number    INTEGER NULL;

-- 4. Indexes and uniqueness guards for fast, duplicate-safe look-up
CREATE INDEX IF NOT EXISTS idx_waitlist_founding_number ON waitlist (founding_number);
CREATE INDEX IF NOT EXISTS idx_profiles_founding_number ON profiles (founding_number) WHERE founding_number IS NOT NULL;
CREATE UNIQUE INDEX IF NOT EXISTS waitlist_email_lower_unique_idx ON waitlist (lower(email));
CREATE UNIQUE INDEX IF NOT EXISTS waitlist_founding_number_unique_idx ON waitlist (founding_number) WHERE founding_number IS NOT NULL;


-- --------------------------------------------------
-- Migration: 016_birth_profiles.sql
-- --------------------------------------------------

-- ─── Migration 016: Birth Profiles ──────────────────────────────────────────
-- Stores Kundali birth data for registered users (multiple profiles per account)
-- and guest users (session_token based, claimed on signup).
-- Chart data computed once and stored — never recalculated.
-- Global-ready: stores IANA timezone for any birth location worldwide.

create table if not exists birth_profiles (
  id              uuid primary key default gen_random_uuid(),
  -- null owner_id = guest profile (temporary, claimed on signup)
  owner_id        uuid references profiles(id) on delete cascade,

  -- Who this profile is for
  label           text not null default 'My Chart',   -- 'Me', 'Priya (Wife)', 'Arjun (Son)'
  full_name       text,
  relation        text check (relation in (
                    'self','spouse','child','parent','sibling','friend','other'
                  )) default 'self',

  -- Birth details (always store in local birth timezone)
  date_of_birth   date not null,
  time_of_birth   time,                    -- null = unknown birth time
  birth_city      text,
  birth_country   text,
  birth_lat       numeric(9,6),
  birth_lng       numeric(9,6),
  birth_timezone  text,                    -- IANA e.g. 'Asia/Kolkata', 'America/New_York'

  -- Computed & stored (never recalculate — call once, keep forever)
  rashi           text,                    -- Moon sign rashi name
  sun_rashi       text,                    -- Sun sign rashi name
  nakshatra       text,                    -- Birth nakshatra
  nakshatra_pada  smallint,               -- 1-4
  nakshatra_lord  text,                    -- Planet lord
  lagna           text,                    -- Ascendant rashi
  lagna_deg       numeric(6,3),           -- Exact degree within lagna rashi
  ayanamsa        numeric(6,4),           -- Lahiri ayanamsa at birth
  chart_data      jsonb,                   -- Full planet positions, house cusps, dasha

  -- Dasha quick-access (for notifications & home card)
  current_dasha_planet   text,
  current_dasha_end_date date,
  next_dasha_planet      text,

  -- Profile meta
  is_primary      boolean default false,   -- User's own chart
  is_public       boolean default false,   -- Future: shareable via link

  -- Guest session support (claimed on signup, owner_id then set)
  session_token   text,

  created_at      timestamptz default now(),
  updated_at      timestamptz default now()
);

-- ── Indexes ──────────────────────────────────────────────────────────────────
create index if not exists idx_birth_profiles_owner
  on birth_profiles(owner_id);

create index if not exists idx_birth_profiles_primary
  on birth_profiles(owner_id) where is_primary = true;

create index if not exists idx_birth_profiles_session
  on birth_profiles(session_token) where session_token is not null;

-- Partial index for daily Rashiphal notifications (users with known rashi)
create index if not exists idx_birth_profiles_rashi_notify
  on birth_profiles(owner_id, rashi)
  where is_primary = true and rashi is not null;

-- Enforce one primary profile per authenticated user at DB level
create unique index if not exists idx_birth_profiles_one_primary
  on birth_profiles(owner_id)
  where is_primary = true and owner_id is not null;

-- ── Row Level Security ────────────────────────────────────────────────────────
alter table birth_profiles enable row level security;

-- Authenticated users can manage their own profiles
create policy "Users manage own birth profiles"
  on birth_profiles for all
  using (auth.uid() = owner_id)
  with check (auth.uid() = owner_id);

-- Guest profiles readable by anyone with the session token (handled in API layer)
-- No RLS policy for guests — API routes check session_token manually

-- ── Auto-update timestamp ─────────────────────────────────────────────────────
create or replace function update_birth_profiles_updated_at()
returns trigger language plpgsql as $$
begin
  new.updated_at = now();
  return new;
end;
$$;

create trigger birth_profiles_updated_at
  before update on birth_profiles
  for each row execute function update_birth_profiles_updated_at();


-- --------------------------------------------------
-- Migration: 017_birth_profiles_upsert.sql
-- --------------------------------------------------

-- ─── Migration 017: Birth Profiles — upsert safety & RLS fix ────────────────
-- Fixes the unique-primary constraint violation when auto-saving a second chart.
-- Also adds service-role bypass policy needed for guest claim flow.

-- 1. Drop the strict unique index (API already unsets existing primary first,
--    but race conditions can still trigger the constraint).
drop index if exists idx_birth_profiles_one_primary;

-- 2. Re-create as a regular (non-unique) index for fast ordering.
create index if not exists idx_birth_profiles_primary_order
  on birth_profiles(owner_id, is_primary desc)
  where owner_id is not null;

-- 3. Allow service-role key to bypass RLS (needed for API routes & claim flow).
--    PostgreSQL does not support CREATE POLICY IF NOT EXISTS, so use a DO block.
do $$ begin
  if not exists (
    select 1 from pg_policies
    where schemaname = 'public'
      and tablename  = 'birth_profiles'
      and policyname = 'Service role full access'
  ) then
    create policy "Service role full access"
      on birth_profiles for all
      to service_role
      using (true)
      with check (true);
  end if;
end $$;


